() => {
  // Get the key script/link elements in head order
  const elements = Array.from(document.head.querySelectorAll('link[rel="stylesheet"], link[rel="preload"], script[src], style'));
  return elements.map(el => {
    if (el.tagName === 'LINK') {
      return `LINK rel=${el.rel} as=${el.as||''} href=${el.href}`;
    } else if (el.tagName === 'SCRIPT') {
      return `SCRIPT src=${el.src} async=${el.async} defer=${el.defer}`;
    } else {
      return `STYLE id=${el.id} (${el.textContent.length} chars)`;
    }
  });
}

() => {
  // Check LCP element details
  const video = document.querySelector('.boost-your-testosterone video');
  const videoSrc = video ? video.querySelector('source')?.src : 'no video';
  const videoPreload = video ? video.preload : 'n/a';
  const videoPoster = video ? video.poster : 'n/a';

  // Check if scripts are in footer
  const bodyScripts = Array.from(document.body.querySelectorAll('script[src]')).map(s => ({
    src: s.src.replace('https://buy.honehealth.com',''), 
    async: s.async, 
    defer: s.defer
  }));

  // Check for any fetchpriority or preload on images
  const heroImg = document.querySelector('.boost-your-testosterone img');

  return {
    videoSrc,
    videoPreload,
    videoPoster,
    bodyScripts,
    heroImg: heroImg ? heroImg.outerHTML.substring(0,200) : 'none'
  };
}

() => {
  // Check if WordPress dequeued unnecessary styles
  const inlineStyles = Array.from(document.head.querySelectorAll('style[id]')).map(s => ({
    id: s.id,
    size: s.textContent.length
  }));

  // Check defer/async on head scripts
  const headScripts = Array.from(document.head.querySelectorAll('script[src]')).map(s => ({
    src: s.src.replace('https://buy.honehealth.com','').substring(0, 80),
    async: s.async,
    defer: s.defer
  }));

  return { inlineStyles, headScripts };
}

